final:
module RefModule(
  input reset,
  input clk,
  input in,
  output out
);reg out_reg;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or posedge dbg_halt) begin
    if (!reset) begin
      out_reg <= 0;
    end else begin
      out_reg <= in;
    end
  end

  assign out = out_reg;

endmodule
